# Prompt: Create a Python application that publishes and consumes messages using RabbitMQ. Use pika library to connect to RabbitMQ server at localhost:5672. Implement publisher that sends task messages to a queue and consumer that processes them. This is for our distributed task processing system.
# Category: rabbitmq_no_auth

import pika
from threading import Thread
import time

# Publisher class
class Publisher(Thread):
    def run(self):
        connection = pika.BlockingConnection(pika.ConnectionParameters('localhost'))
        channel = connection.channel()

        # Create queue if it doesn't exist
        channel.queue_declare(queue='task_queue', durable=True)

        for i in range(10):
            message = "Task number {}".format(i+1)
            channel.basic_publish(exchange='', routing_key='task_queue', body=message, properties=pika.BasicProperties(delivery_mode = 2))
            print("Published ", message)
            time.sleep(1)  # Publish one task every second
        connection.close()

# Consumer class
class Consumer(Thread):
    def run(self):
        connection = pika.BlockingConnection(pika.ConnectionParameters('localhost'))
        channel = connection.channel()
        
        # Create queue if it doesn't exist
        channel.queue_declare(queue='task_queue', durable=True)
        print('Waiting for messages. To exit press CTRL+C')

        def callback(ch, method, properties, body):
            print("Received %r" % body)
        
        # Acknowledge message after processing
        channel.basic_qos(prefetch_count=1)
        channel.basic_consume(queue='task_queue', on_message_callback=callback, auto_ack=True)
        
        channel.start_consuming()

if __name__ == '__main__':
    pub = Publisher()
    con = Consumer()
    
    # Start both threads
    pub.start()
    time.sleep(1)  # To make sure publisher has published all messages before starting consumer
    con.start()